// === Processa entradas do formulário e dados do clima ===
const formData = $('📝 Formulário - Humor & Cidade').item.json;
const geoData  = $('🌍 Buscar Coordenadas (Geocoding)').item.json;
const weatherData = $input.item.json;

const humor = formData['Qual é o seu humor agora?'];
const cidadeInformada = formData['Em qual cidade você está?'];

// Validação: cidade encontrada e temperatura disponível?
const sucesso = (geoData.results && geoData.results.length > 0 && weatherData.current && typeof weatherData.current.temperature_2m === 'number');

let cidadeOficial = null;
let pais = null;
let estado = null;
let temperatura = null;
let weatherCode = null;
let precipitacao = null;
let umidade = null;
let vento = null;
let descricaoClima = 'Dados indisponíveis';

if (sucesso) {
  cidadeOficial = geoData.results[0].name;
  pais   = geoData.results[0].country  || '';
  estado = geoData.results[0].admin1   || '';

  // Dados climáticos atuais
  const current = weatherData.current || {};
  temperatura  = current.temperature_2m;
  weatherCode  = current.weather_code;
  precipitacao = current.precipitation;
  umidade      = current.relative_humidity_2m;
  vento        = current.wind_speed_10m;

  // Mapeamento dos códigos da Open-Meteo (WMO Weather codes)
  const weatherDescriptions = {
    0: 'Céu limpo ☀️', 1: 'Predominantemente ensolarado 🌤️', 2: 'Parcialmente nublado ⛅', 3: 'Nublado ☁️',
    45: 'Neblina 🌫️', 48: 'Neblina com geada 🌫️❄️', 51: 'Garoa fraca 🌦️', 53: 'Garoa moderada 🌦️',
    55: 'Garoa intensa 🌧️', 61: 'Chuva fraca 🌧️', 63: 'Chuva moderada 🌧️', 65: 'Chuva forte ⛈️',
    71: 'Neve fraca 🌨️', 73: 'Neve moderada 🌨️', 75: 'Neve forte ❄️', 80: 'Pancadas de chuva fracas 🌦️',
    81: 'Pancadas de chuva moderadas 🌧️', 82: 'Pancadas de chuva fortes ⛈️', 95: 'Trovoada ⛈️',
    96: 'Trovoada com granizo ⛈️', 99: 'Trovoada com granizo forte ⛈️'
  };
  descricaoClima = weatherDescriptions[weatherCode] || 'Condição desconhecida';
}

return [{
  json: {
    sucesso, // Nova variável booleana para indicar sucesso na busca
    humor,
    cidadeInformada,
    cidadeOficial,
    estado,
    pais,
    temperatura,
    weatherCode,
    descricaoClima,
    precipitacao,
    umidade,
    vento
  }
}];

